/**
 * @summary List shared-inbox threads, optionally filtered by status and owner.
 */
export const getListInboxThreadsUrl = (params?: ListInboxThreadsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/inbox/threads?${stringifiedParams}`
    : `/api/inbox/threads`;
};

export const listInboxThreads = async (
  params?: ListInboxThreadsParams,
  options?: RequestInit,
): Promise<InboxThreadSummary[]> => {
  return customFetch<InboxThreadSummary[]>(getListInboxThreadsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListInboxThreadsQueryKey = (
  params?: ListInboxThreadsParams,
) => {
  return [`/api/inbox/threads`, ...(params ? [params] : [])] as const;
};

export const getListInboxThreadsQueryOptions = <
  TData = Awaited<ReturnType<typeof listInboxThreads>>,
  TError = ErrorType<unknown>,
>(
  params?: ListInboxThreadsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listInboxThreads>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListInboxThreadsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listInboxThreads>>
  > = ({ signal }) => listInboxThreads(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listInboxThreads>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

